// Determine current context for content generation
const now = new Date();
const month = now.toLocaleString('en-US', { month: 'long' });
const monthNum = now.getMonth();

// Determine season
let season;
if (monthNum >= 2 && monthNum <= 4) season = 'Spring';
else if (monthNum >= 5 && monthNum <= 7) season = 'Summer';
else if (monthNum >= 8 && monthNum <= 10) season = 'Fall';
else season = 'Winter';

// Calculate batch_week (Monday of this week)
const monday = new Date(now);
monday.setDate(now.getDate() - ((now.getDay() + 6) % 7));
monday.setHours(0, 0, 0, 0);
const batchWeek = monday.toISOString().split('T')[0];

// Pillar assignments by day_of_week
const pillars = [
  { day_of_week: 1, pillar: 'tips', post_type: 'tip', label: 'Monday - Tips' },
  { day_of_week: 2, pillar: 'before_after', post_type: 'showcase', label: 'Tuesday - Before/After' },
  { day_of_week: 3, pillar: 'review_spotlight', post_type: 'review', label: 'Wednesday - Review Spotlight' },
  { day_of_week: 4, pillar: 'seasonal', post_type: 'seasonal', label: 'Thursday - Seasonal' },
  { day_of_week: 5, pillar: 'community', post_type: 'community', label: 'Friday - Community' },
  { day_of_week: 6, pillar: 'education', post_type: 'education', label: 'Saturday - Education' },
  { day_of_week: 0, pillar: 'promo', post_type: 'promo', label: 'Sunday - Promo' }
];

return [{
  json: {
    month,
    season,
    batchWeek,
    pillars,
    year: now.getFullYear()
  }
}];

// Parse the AI response and prepare posts for insertion
const aiResponse = $input.first().json;
const content = aiResponse.content[0].text;

// Parse JSON from response
let posts;
try {
  posts = JSON.parse(content);
} catch (e) {
  // Try extracting JSON array from response
  const match = content.match(/\[\s*\{[\s\S]*\}\s*\]/);
  if (match) {
    posts = JSON.parse(match[0]);
  } else {
    throw new Error('Failed to parse AI response as JSON: ' + content.substring(0, 200));
  }
}

// Validate we got 7 posts
if (!Array.isArray(posts) || posts.length !== 7) {
  throw new Error(`Expected 7 posts, got ${Array.isArray(posts) ? posts.length : 'non-array'}`);
}

const batchWeek = $('Get Current Context').item.json.batchWeek;
const mondayDate = new Date(batchWeek + 'T00:00:00Z');

// Map day_of_week to offset from Monday
const dayOffsets = { 1: 0, 2: 1, 3: 2, 4: 3, 5: 4, 6: 5, 0: 6 };

const enrichedPosts = posts.map(post => {
  const offset = dayOffsets[post.day_of_week];
  const postDate = new Date(mondayDate);
  postDate.setDate(mondayDate.getDate() + offset);
  // Schedule for 10:00 AM CT (UTC-5 standard / UTC-6 daylight)
  // Use 15:00 UTC as approximate 10am CT (CDT)
  postDate.setUTCHours(15, 0, 0, 0);

  return {
    post_text: post.post_text,
    image_url: null,
    platforms: post.platforms || ['instagram', 'google_business_profile'],
    post_type: post.post_type,
    pillar: post.pillar,
    day_of_week: post.day_of_week,
    scheduled_for: postDate.toISOString(),
    status: 'scheduled',
    batch_week: batchWeek,
    source: post.pillar === 'review_spotlight' ? 'review_highlight' : 'ai_generated',
    engagement_data: {}
  };
});

return enrichedPosts.map(p => ({ json: p }));

